return {
  json: {
    from: $json.from,
    subject: $json.subject,
    text: $json.text || $json.html || '',
    date: $json.date
  }
};

const items = $input.all();

return items.map(item => {
  let text =
    item.json.output?.[0]?.content?.[0]?.text ||
    item.json.message?.content ||
    item.json.choices?.[0]?.message?.content ||
    item.json.text ||
    item.json.content ||
    '';

  text = String(text)
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  if (!text) {
    throw new Error('Kein KI-Text gefunden. Prüfe den Output vom OpenAI Node.');
  }

  const match = text.match(/\{[\s\S]*\}/);

  if (!match) {
    throw new Error('Kein JSON im KI-Output gefunden: ' + text);
  }

  const ai = JSON.parse(match[0]);

  return {
    json: {
      ...item.json,
      ai
    }
  };
});

